"use strict";const hamburgerBtn=document.querySelector(".hamburger-btn"),mainNav=document.querySelector("#main-nav"),mainNavList=document.querySelector(".main-nav-list");hamburgerBtn.addEventListener("click",()=>{let e=mainNav.classList.toggle("nav-open");hamburgerBtn.setAttribute("aria-expanded",e?"true":"false")}),mainNavList.addEventListener("click",e=>{"A"===e.target.tagName&&(mainNav.classList.remove("nav-open"),hamburgerBtn.setAttribute("aria-expanded","false"))});const tabsBtns=document.querySelectorAll(".tab"),tabPanels=document.querySelectorAll(".tab-panel");function onTabClick(e){tabsBtns.forEach(e=>e.classList.remove("selected")),tabsBtns.forEach(e=>e.setAttribute("aria-selected","false"));let t=e.currentTarget;t.classList.add("selected"),t.setAttribute("aria-selected","true");let a=t.dataset.target;tabPanels.forEach(e=>e.classList.remove("selected")),document.getElementById(a).classList.add("selected")}tabsBtns.forEach(e=>e.addEventListener("click",onTabClick));const accordionBtns=document.querySelectorAll(".accordion-btn");function onAccordionBtnClick(e){let t=e.currentTarget,a=t.closest(".accordion-item").classList.toggle("expanded");t.setAttribute("aria-expanded",a?"true":"false")}accordionBtns.forEach(e=>e.addEventListener("click",onAccordionBtnClick));